     1→#!/usr/bin/env node
     2→// FreeLang v6: CLI + REPL
     3→
     4→import * as fs from "fs";
     5→import * as path from "path";
     6→import * as readline from "readline";
     7→import { run } from "./index";
     8→import { lex } from "./lexer";
     9→import { parse } from "./parser";
    10→import { compile } from "./compiler";
    11→import { VM } from "./vm";
    12→
    13→const VERSION = "6.0.0";
    14→
    15→function usage() {
    16→  console.log(`FreeLang v${VERSION}
    17→Usage:
    18→  freelang run <file>     Run a .fl file
    19→  freelang eval "<code>"  Evaluate code string
    20→  freelang repl           Start interactive REPL
    21→  freelang --version      Show version
    22→  freelang --help         Show help`);
    23→}
    24→
    25→function runFile(filePath: string) {
    26→  const resolved = path.resolve(filePath);
    27→  if (!fs.existsSync(resolved)) {
    28→    console.error(`Error: File not found: ${resolved}`);
    29→    process.exit(1);
    30→  }
    31→  const source = fs.readFileSync(resolved, "utf-8");
    32→  try {
    33→    const output = run(source, path.dirname(resolved));
    34→    for (const line of output) process.stdout.write(line);
    35→  } catch (e: any) {
    36→    console.error(e.message);
    37→    process.exit(1);
    38→  }
    39→}
    40→
    41→function evalCode(code: string) {
    42→  try {
    43→    const output = run(code);
    44→    for (const line of output) process.stdout.write(line);
    45→  } catch (e: any) {
    46→    console.error(e.message);
    47→    process.exit(1);
    48→  }
    49→}
    50→
    51→function startRepl() {
    52→  console.log(`FreeLang v${VERSION} REPL (type "exit" to quit)`);
    53→  const rl = readline.createInterface({ input: process.stdin, output: process.stdout, prompt: ">> " });
    54→
    55→  // Persistent VM state for REPL
    56→  let globals = new Map<string, any>();
    57→
    58→  rl.prompt();
    59→  rl.on("line", (line) => {
    60→    const input = line.trim();
    61→    if (input === "exit" || input === "quit") { rl.close(); return; }
    62→    if (input === "") { rl.prompt(); return; }
    63→    try {
    64→      const tokens = lex(input);
    65→      const ast = parse(tokens);
    66→      const chunk = compile(ast);
    67→      const vm = new VM(chunk, globals);
    68→      const result = vm.run();
    69→      globals = vm.getGlobals();
    70→      for (const line of result.output) process.stdout.write(line);
    71→    } catch (e: any) {
    72→      console.error(`Error: ${e.message}`);
    73→    }
    74→    rl.prompt();
    75→  });
    76→  rl.on("close", () => { console.log("Bye!"); process.exit(0); });
    77→}
    78→
    79→// Main
    80→const args = process.argv.slice(2);
    81→if (args.length === 0 || args[0] === "repl") {
    82→  startRepl();
    83→} else if (args[0] === "run" && args[1]) {
    84→  runFile(args[1]);
    85→} else if (args[0] === "eval" && args[1]) {
    86→  evalCode(args[1]);
    87→} else if (args[0] === "--version" || args[0] === "-v") {
    88→  console.log(`FreeLang v${VERSION}`);
    89→} else if (args[0] === "--help" || args[0] === "-h") {
    90→  usage();
    91→} else if (args[0].endsWith(".fl") || args[0].endsWith(".freelang")) {
    92→  runFile(args[0]);
    93→} else {
    94→  usage();
    95→  process.exit(1);
    96→}
