     1→// FreeLang v6: Virtual Machine
     2→
     3→import { Op, Value, Chunk } from "./compiler";
     4→import { getBuiltins } from "./stdlib/builtins";
     5→
     6→type BuiltinFn = (args: Value[], vm: VM) => Value;
     7→type Frame = { retAddr: number; baseSlot: number; fn: string; upvalues: Value[] };
     8→type TryHandler = { catchAddr: number; stackDepth: number; frameDepth: number };
     9→
    10→export class VM {
    11→  private stack: Value[] = [];
    12→  private globals = new Map<string, Value>();
    13→  private frames: Frame[] = [];
    14→  private tryStack: TryHandler[] = [];
    15→  private ip = 0;
    16→  private output: string[] = [];
    17→  private builtinFns: Record<string, BuiltinFn>;
    18→
    19→  constructor(private chunk: Chunk, initialGlobals?: Map<string, Value>) {
    20→    this.builtinFns = getBuiltins();
    21→    // Register builtins
    22→    for (const name of Object.keys(this.builtinFns)) {
    23→      this.globals.set(name, { tag: "builtin", name });
    24→    }
    25→    // Restore persisted globals (e.g. from REPL)
    26→    if (initialGlobals) {
    27→      for (const [k, v] of initialGlobals) {
    28→        if (!this.globals.has(k)) this.globals.set(k, v);
    29→      }
    30→    }
    31→  }
    32→
    33→  getGlobals(): Map<string, Value> { return new Map(this.globals); }
    34→
    35→  run(): { output: string[]; result: Value } {
    36→    while (this.ip < this.chunk.code.length) {
    37→      const op = this.chunk.code[this.ip++];
    38→      if (op === Op.Halt) {
    39→        return { output: this.output, result: this.stack.length > 0 ? this.peek() : { tag: "null" } };
    40→      }
    41→      this.execOp(op);
    42→    }
    43→    return { output: this.output, result: { tag: "null" } };
    44→  }
    45→
    46→  // Public API for builtins
    47→  getGlobal(name: string): Value | undefined { return this.globals.get(name); }
    48→  setGlobal(name: string, val: Value) { this.globals.set(name, val); }
    49→  getOutput(): string[] { return this.output; }
    50→  addOutput(s: string) { this.output.push(s); }
    51→
    52→  /** Call a FreeLang fn or builtin Value from within a builtin (HOFs). */
    53→  callValue(callee: Value, args: Value[]): Value {
    54→    if (callee.tag === "builtin") {
    55→      return this.builtinFns[callee.name](args, this);
    56→    }
    57→    if (callee.tag === "fn") {
    58→      const savedIp = this.ip;
    59→      const targetFrameDepth = this.frames.length;
    60→
    61→      // Mimic Call opcode: push callee + args, push frame
    62→      this.stack.push(callee);
    63→      for (const a of args) this.stack.push(a);
    64→      this.frames.push({
    65→        retAddr: savedIp,
    66→        baseSlot: this.stack.length - args.length,
    67→        fn: callee.name,
    68→        upvalues: callee.freeVars,
    69→      });
    70→      this.ip = callee.addr;
    71→
    72→      // Execute until our frame is popped by Return
    73→      while (this.frames.length > targetFrameDepth) {
    74→        const op = this.chunk.code[this.ip++];
    75→        this.execOp(op);
    76→      }
    77→      // Return handler pushed the result onto the stack and restored ip
    78→      return this.stack.pop()!;
    79→    }
    80→    throw new Error(`Cannot call ${callee.tag}`);
    81→  }
    82→
    83→  stringify(v: Value): string {
    84→    switch (v.tag) {
    85→      case "num": return String(v.val);
    86→      case "str": return v.val;
    87→      case "bool": return String(v.val);
    88→      case "null": return "null";
    89→      case "array": return "[" + v.val.map(e => this.stringify(e)).join(", ") + "]";
    90→      case "object": {
    91→        const entries = Array.from(v.val.entries()).map(([k, v2]) => `${k}: ${this.stringify(v2)}`);
    92→        return "{" + entries.join(", ") + "}";
    93→      }
    94→      case "fn": return `<fn ${v.name}>`;
    95→      case "builtin": return `<builtin ${v.name}>`;
    96→      default: return "<unknown>";
    97→    }
    98→  }
    99→
   100→  // --- Private internals ---
   101→
   102→  private execOp(op: number) {
   103→    switch (op) {
   104→      case Op.Const: this.stack.push(this.chunk.constants[this.chunk.code[this.ip++]]); break;
   105→      case Op.Pop: this.stack.pop(); break;
   106→      case Op.Dup: this.stack.push(this.peek()); break;
   107→
   108→      // Arithmetic
   109→      case Op.Add: { const b = this.pop(), a = this.pop(); this.stack.push(this.add(a, b)); break; }
   110→      case Op.Sub: { const b = this.popNum(), a = this.popNum(); this.stack.push(num(a - b)); break; }
   111→      case Op.Mul: { const b = this.popNum(), a = this.popNum(); this.stack.push(num(a * b)); break; }
   112→      case Op.Div: { const b = this.popNum(), a = this.popNum(); if (b === 0) this.runtimeError("Division by zero"); this.stack.push(num(a / b)); break; }
   113→      case Op.Mod: { const b = this.popNum(), a = this.popNum(); this.stack.push(num(a % b)); break; }
   114→      case Op.Neg: this.stack.push(num(-this.popNum())); break;
   115→
   116→      // Comparison
   117→      case Op.Eq: { const b = this.pop(), a = this.pop(); this.stack.push(bool(this.valEq(a, b))); break; }
   118→      case Op.Neq: { const b = this.pop(), a = this.pop(); this.stack.push(bool(!this.valEq(a, b))); break; }
   119→      case Op.Lt: { const b = this.popNum(), a = this.popNum(); this.stack.push(bool(a < b)); break; }
   120→      case Op.Gt: { const b = this.popNum(), a = this.popNum(); this.stack.push(bool(a > b)); break; }
   121→      case Op.Lte: { const b = this.popNum(), a = this.popNum(); this.stack.push(bool(a <= b)); break; }
   122→      case Op.Gte: { const b = this.popNum(), a = this.popNum(); this.stack.push(bool(a >= b)); break; }
   123→
   124→      // Logic
   125→      case Op.And: { const b = this.pop(), a = this.pop(); this.stack.push(bool(this.truthy(a) && this.truthy(b))); break; }
   126→      case Op.Or: { const b = this.pop(), a = this.pop(); this.stack.push(bool(this.truthy(a) || this.truthy(b))); break; }
   127→      case Op.Not: this.stack.push(bool(!this.truthy(this.pop()))); break;
   128→
   129→      // Jump
   130→      case Op.Jump: this.ip = this.chunk.code[this.ip]; break;
   131→      case Op.JumpIfFalse: { const addr = this.chunk.code[this.ip++]; if (!this.truthy(this.pop())) this.ip = addr; break; }
   132→      case Op.JumpIfTrue: { const addr = this.chunk.code[this.ip++]; if (this.truthy(this.pop())) this.ip = addr; break; }
   133→
   134→      // Variables
   135→      case Op.Load: { const slot = this.chunk.code[this.ip++]; this.stack.push(this.stack[this.baseSlot() + slot]); break; }
   136→      case Op.Store: { const slot = this.chunk.code[this.ip++]; this.stack[this.baseSlot() + slot] = this.peek(); break; }
   137→      case Op.LoadGlobal: {
   138→        const name = this.chunk.constants[this.chunk.code[this.ip++]] as { tag: "str"; val: string };
   139→        const val = this.globals.get(name.val);
   140→        if (val === undefined) this.runtimeError(`Undefined variable '${name.val}'`);
   141→        this.stack.push(val!);
   142→        break;
   143→      }
   144→      case Op.StoreGlobal: {
   145→        const name = this.chunk.constants[this.chunk.code[this.ip++]] as { tag: "str"; val: string };
   146→        this.globals.set(name.val, this.pop());
   147→        break;
   148→      }
   149→
   150→      // Functions
   151→      case Op.Call: {
   152→        const argc = this.chunk.code[this.ip++];
   153→        const callee = this.stack[this.stack.length - 1 - argc];
   154→        if (callee.tag === "fn") {
   155→          this.frames.push({ retAddr: this.ip, baseSlot: this.stack.length - argc, fn: callee.name, upvalues: callee.freeVars });
   156→          this.ip = callee.addr;
   157→        } else if (callee.tag === "builtin") {
   158→          const args = this.stack.splice(this.stack.length - argc, argc);
   159→          this.stack.pop(); // pop callee
   160→          const result = this.builtinFns[callee.name](args, this);
   161→          this.stack.push(result);
   162→        } else {
   163→          this.runtimeError(`Cannot call ${callee.tag}`);
   164→        }
   165→        break;
   166→      }
   167→      case Op.Return: {
   168→        const result = this.pop();
   169→        const frame = this.frames.pop()!;
   170→        this.stack.length = frame.baseSlot - 1; // remove locals + callee
   171→        this.stack.push(result);
   172→        this.ip = frame.retAddr;
   173→        break;
   174→      }
   175→
   176→      // Array
   177→      case Op.NewArray: {
   178→        const len = this.chunk.code[this.ip++];
   179→        const elements = this.stack.splice(this.stack.length - len, len);
   180→        this.stack.push({ tag: "array", val: elements });
   181→        break;
   182→      }
   183→      case Op.Index: {
   184→        const idx = this.pop();
   185→        const obj = this.pop();
   186→        if (obj.tag === "array" && idx.tag === "num") {
   187→          this.stack.push(obj.val[Math.floor(idx.val)] ?? { tag: "null" });
   188→        } else if (obj.tag === "object" && idx.tag === "str") {
   189→          this.stack.push(obj.val.get(idx.val) ?? { tag: "null" });
   190→        } else if (obj.tag === "str" && idx.tag === "num") {
   191→          const ch = obj.val[Math.floor(idx.val)];
   192→          this.stack.push(ch ? { tag: "str", val: ch } : { tag: "null" });
   193→        } else {
   194→          this.stack.push({ tag: "null" });
   195→        }
   196→        break;
   197→      }
   198→      case Op.SetIndex: {
   199→        const idx = this.pop();
   200→        const obj = this.pop();
   201→        const val = this.pop();
   202→        if (obj.tag === "array" && idx.tag === "num") obj.val[Math.floor(idx.val)] = val;
   203→        else if (obj.tag === "object" && idx.tag === "str") obj.val.set(idx.val, val);
   204→        this.stack.push(val);
   205→        break;
   206→      }
   207→
   208→      // Object
   209→      case Op.NewObject: {
   210→        const count = this.chunk.code[this.ip++];
   211→        const map = new Map<string, Value>();
   212→        const items = this.stack.splice(this.stack.length - count * 2, count * 2);
   213→        for (let i = 0; i < items.length; i += 2) {
   214→          map.set((items[i] as { tag: "str"; val: string }).val, items[i + 1]);
   215→        }
   216→        this.stack.push({ tag: "object", val: map });
   217→        break;
   218→      }
   219→      case Op.GetProp: {
   220→        const name = this.chunk.constants[this.chunk.code[this.ip++]] as { tag: "str"; val: string };
   221→        const obj = this.pop();
   222→        if (obj.tag === "object") this.stack.push(obj.val.get(name.val) ?? { tag: "null" });
   223→        else if (obj.tag === "array" && name.val === "length") this.stack.push(num(obj.val.length));
   224→        else if (obj.tag === "str" && name.val === "length") this.stack.push(num(obj.val.length));
   225→        else this.stack.push({ tag: "null" });
   226→        break;
   227→      }
   228→      case Op.SetProp: {
   229→        const propName = this.pop();
   230→        const obj = this.pop();
   231→        const val = this.peek();
   232→        if (obj.tag === "object" && propName.tag === "str") obj.val.set(propName.val, val);
   233→        break;
   234→      }
   235→
   236→      // Closures
   237→      case Op.NewClosure: {
   238→        const numFree = this.chunk.code[this.ip++];
   239→        const fnVal = this.pop();
   240→        if (fnVal.tag !== "fn") this.runtimeError("NewClosure expects fn");
   241→        const freeVars: Value[] = new Array(numFree);
   242→        for (let i = numFree - 1; i >= 0; i--) freeVars[i] = this.pop();
   243→        this.stack.push({ tag: "fn", name: fnVal.name, arity: fnVal.arity, addr: fnVal.addr, freeVars });
   244→        break;
   245→      }
   246→      case Op.LoadFree: {
   247→        const idx = this.chunk.code[this.ip++];
   248→        const frame = this.frames[this.frames.length - 1];
   249→        this.stack.push(frame.upvalues[idx]);
   250→        break;
   251→      }
   252→      case Op.StoreFree: {
   253→        const idx = this.chunk.code[this.ip++];
   254→        const frame = this.frames[this.frames.length - 1];
   255→        frame.upvalues[idx] = this.peek();
   256→        break;
   257→      }
   258→
   259→      // Print
   260→      case Op.Print: this.output.push(this.stringify(this.pop())); break;
   261→      case Op.Println: this.output.push(this.stringify(this.pop()) + "\n"); break;
   262→
   263→      // Try/Catch
   264→      case Op.TryBegin: {
   265→        const catchAddr = this.chunk.code[this.ip++];
   266→        this.tryStack.push({ catchAddr, stackDepth: this.stack.length, frameDepth: this.frames.length });
   267→        break;
   268→      }
   269→      case Op.TryEnd: this.tryStack.pop(); break;
   270→      case Op.Throw: {
   271→        const err = this.pop();
   272→        this.handleError(err);
   273→        break;
   274→      }
   275→
   276→      // Iterator
   277→      case Op.Iter: {
   278→        const val = this.pop();
   279→        if (val.tag === "array") this.stack.push({ tag: "iter", val: val.val, idx: 0 });
   280→        else if (val.tag === "str") this.stack.push({ tag: "iter", val: val.val.split("").map(c => ({ tag: "str", val: c } as Value)), idx: 0 });
   281→        else this.runtimeError("Cannot iterate over " + val.tag);
   282→        break;
   283→      }
   284→      case Op.IterNext: {
   285→        const iter = this.pop();
   286→        if (iter.tag === "iter") {
   287→          this.stack.push(iter.val[iter.idx] ?? { tag: "null" });
   288→          iter.idx++;
   289→        } else {
   290→          this.stack.push({ tag: "null" });
   291→        }
   292→        break;
   293→      }
   294→      case Op.IterDone: {
   295→        const iter = this.pop();
   296→        this.stack.push(bool(iter.tag === "iter" && iter.idx >= iter.val.length));
   297→        break;
   298→      }
   299→
   300→      default: this.runtimeError(`Unknown opcode ${op}`);
   301→    }
   302→  }
   303→
   304→  private peek(): Value { return this.stack[this.stack.length - 1]; }
   305→  private pop(): Value { return this.stack.pop()!; }
   306→  private baseSlot(): number { return this.frames.length > 0 ? this.frames[this.frames.length - 1].baseSlot : 0; }
   307→
   308→  private popNum(): number {
   309→    const v = this.pop();
   310→    if (v.tag !== "num") this.runtimeError(`Expected number, got ${v.tag}`);
   311→    return (v as any).val;
   312→  }
   313→
   314→  private add(a: Value, b: Value): Value {
   315→    if (a.tag === "num" && b.tag === "num") return num(a.val + b.val);
   316→    if (a.tag === "str" || b.tag === "str") return { tag: "str", val: this.stringify(a) + this.stringify(b) };
   317→    if (a.tag === "array" && b.tag === "array") return { tag: "array", val: [...a.val, ...b.val] };
   318→    return num(0);
   319→  }
   320→
   321→  private valEq(a: Value, b: Value): boolean {
   322→    if (a.tag !== b.tag) return false;
   323→    if (a.tag === "null") return true;
   324→    if (a.tag === "num" || a.tag === "str" || a.tag === "bool") return (a as any).val === (b as any).val;
   325→    return a === b;
   326→  }
   327→
   328→  private truthy(v: Value): boolean {
   329→    if (v.tag === "null") return false;
   330→    if (v.tag === "bool") return v.val;
   331→    if (v.tag === "num") return v.val !== 0;
   332→    if (v.tag === "str") return v.val !== "";
   333→    if (v.tag === "array") return v.val.length > 0;
   334→    return true;
   335→  }
   336→
   337→  private handleError(err: Value) {
   338→    if (this.tryStack.length > 0) {
   339→      const handler = this.tryStack.pop()!;
   340→      this.stack.length = handler.stackDepth;
   341→      this.frames.length = handler.frameDepth;
   342→      this.stack.push(err);
   343→      this.ip = handler.catchAddr;
   344→    } else {
   345→      throw new Error(`Unhandled error: ${this.stringify(err)}`);
   346→    }
   347→  }
   348→
   349→  private runtimeError(msg: string): never {
   350→    const err: Value = { tag: "str", val: msg };
   351→    if (this.tryStack.length > 0) {
   352→      this.handleError(err);
   353→      throw new Error("CAUGHT");
   354→    }
   355→    throw new Error(`Runtime Error: ${msg}`);
   356→  }
   357→}
   358→
   359→function num(n: number): Value { return { tag: "num", val: n }; }
   360→function bool(b: boolean): Value { return { tag: "bool", val: b }; }
   361→

