     1→// FreeLang v6: Regex builtins (Phase 2)
     2→// Pure JS RegExp-based
     3→
     4→import { Value } from "../compiler";
     5→import { VM } from "../vm";
     6→import { registerBuiltin } from "./builtins";
     7→
     8→function num(n: number): Value { return { tag: "num", val: n }; }
     9→function str(s: string): Value { return { tag: "str", val: s }; }
    10→function bool(b: boolean): Value { return { tag: "bool", val: b }; }
    11→function arr(items: Value[]): Value { return { tag: "array", val: items }; }
    12→function numVal(v: Value): number { return v.tag === "num" ? v.val : 0; }
    13→function strVal(v: Value): string { return v.tag === "str" ? v.val : ""; }
    14→
    15→function makeRe(pattern: string, flags?: string): RegExp | null {
    16→  try { return new RegExp(pattern, flags); }
    17→  catch { return null; }
    18→}
    19→
    20→registerBuiltin("regex_test", (args) => {
    21→  const re = makeRe(strVal(args[0]));
    22→  return re ? bool(re.test(strVal(args[1]))) : bool(false);
    23→});
